import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Quiz, QuizAttemptResult } from '../../core/models';

/**
 * LearnLoop quiz — renders MCQ questions with radio inputs, submits answers,
 * shows the graded score/pass result, and disables submission once the
 * single-attempt limit is exhausted. Loads via ApiService.getQuiz(id).
 * Note: the payload never contains `correctIdx` (hidden server-side).
 */
@Component({
  selector: 'app-quiz-take',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './quiz-take.component.html',
  styleUrl: './quiz-take.component.css',
})
export class QuizTakeComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly submitting = signal(false);
  readonly result = signal<QuizAttemptResult | null>(null);

  readonly quiz = signal<Quiz | null>({
    id: 'q1',
    moduleId: 'm2',
    title: 'CSS Fundamentals Quiz',
    attemptLimit: 1,
    attemptsUsed: 0,
    lastScorePct: null,
    passed: false,
    questions: [
      {
        id: 'qq1',
        quizId: 'q1',
        text: 'Which CSS property changes the text colour of an element?',
        options: ['font-color', 'color', 'text-style', 'foreground'],
      },
      {
        id: 'qq2',
        quizId: 'q1',
        text: 'What does the "C" in CSS stand for?',
        options: ['Cascading', 'Computed', 'Coded', 'Central'],
      },
      {
        id: 'qq3',
        quizId: 'q1',
        text: 'Which selector targets an element by its id attribute?',
        options: ['.name', '#name', '*name', '@name'],
      },
    ],
  });

  // answers[i] = chosen option index for question i.
  answers: number[] = [];
  quizId = '';

  readonly attemptsLeft = computed(() => {
    const q = this.quiz();
    if (!q) return 0;
    return Math.max(0, q.attemptLimit - (q.attemptsUsed ?? 0));
  });
  readonly exhausted = computed(() => this.attemptsLeft() === 0);

  constructor(private api: ApiService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.quizId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loading.set(true);
    this.error.set(null);
    this.api.getQuiz(this.quizId).subscribe({
      next: (quiz) => {
        this.quiz.set(quiz);
        this.answers = new Array((quiz.questions ?? []).length).fill(-1);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load this quiz. Please try again.');
        this.loading.set(false);
      },
    });
  }

  allAnswered(): boolean {
    const q = this.quiz();
    if (!q) return false;
    const count = (q.questions ?? []).length;
    return this.answers.length === count && this.answers.every((a) => a >= 0);
  }

  submit(): void {
    if (this.exhausted() || !this.allAnswered()) return;
    this.submitting.set(true);
    this.error.set(null);
    this.api.submitAttempt(this.quizId, this.answers).subscribe({
      next: (res) => {
        this.result.set(res);
        this.submitting.set(false);
        const q = this.quiz();
        if (q) this.quiz.set({ ...q, attemptsUsed: (q.attemptsUsed ?? 0) + 1 });
      },
      error: (err) => {
        this.submitting.set(false);
        this.error.set(
          err?.status === 409
            ? 'You have used all your attempts for this quiz.'
            : 'Could not submit your answers. Please try again.',
        );
      },
    });
  }
}
